// Summary: Tests Scroller render slots, control visibility, paging steps, stackRows attribute, edge-driven variants, and onScrollChange metrics.

import { act, render, screen } from '@testing-library/react';
import * as React from 'react';
import { Scroller } from './Scroller';

type GeometryConfig = {
  clientWidth: number;
  scrollWidth: number;
};

type GeometryHandle = {
  getScrollLeft(): number;
  setScrollLeft(value: number): void;
  getMaxScrollLeft(): number;
};

const configureGeometry = (element: HTMLDivElement, config: GeometryConfig): GeometryHandle => {
  const { clientWidth, scrollWidth } = config;
  const maxScrollLeft = Math.max(scrollWidth - clientWidth, 0);
  let scrollLeftValue = 0;

  Object.defineProperty(element, 'clientWidth', {
    value: clientWidth,
    configurable: true
  });

  Object.defineProperty(element, 'scrollWidth', {
    value: scrollWidth,
    configurable: true
  });

  Object.defineProperty(element, 'scrollLeft', {
    configurable: true,
    get: () => scrollLeftValue,
    set: value => {
      scrollLeftValue = Math.min(Math.max(value, 0), maxScrollLeft);
    }
  });

  element.scrollBy = ((optionsOrX?: ScrollToOptions | number, y?: number) => {
    const leftDelta = typeof optionsOrX === 'number' ? optionsOrX : (optionsOrX?.left ?? 0);

    scrollLeftValue = Math.min(Math.max(scrollLeftValue + leftDelta, 0), maxScrollLeft);

    if (typeof optionsOrX === 'number' && typeof y === 'number') {
      // Match native signature; vertical scrolling ignored for tests.
      void y;
    }

    element.dispatchEvent(new Event('scroll', { bubbles: true }));
  }) as typeof element.scrollBy;

  return {
    getScrollLeft: () => scrollLeftValue,
    setScrollLeft: value => {
      scrollLeftValue = Math.min(Math.max(value, 0), maxScrollLeft);
    },
    getMaxScrollLeft: () => maxScrollLeft
  };
};

const sampleChildren = Array.from({ length: 8 }, (_, index) => (
  <div
    key={index}
    className="flex h-32 min-w-[14rem] items-center justify-center rounded-md bg-color-background-accent-subtle text-color-content-strong"
  >
    Card {index + 1}
  </div>
));

describe('Scroller', () => {
  it('renders base and rail while toggling controls by showControls', () => {
    const { rerender } = render(<Scroller>{sampleChildren}</Scroller>);
    const viewport = document.querySelector('[data-slot="_viewport"]') as HTMLDivElement;
    configureGeometry(viewport, { clientWidth: 320, scrollWidth: 1600 });

    const initialPresence = {
      base: Boolean(document.querySelector('[data-slot="base"]')),
      rail: Boolean(document.querySelector('[data-slot="_rail"]')),
      controlsWhenTrue: Boolean(document.querySelector('[data-slot="_controls"]'))
    };

    rerender(<Scroller showControls={false}>{sampleChildren}</Scroller>);

    const finalPresence = {
      ...initialPresence,
      controlsWhenFalse: Boolean(document.querySelector('[data-slot="_controls"]'))
    };

    expect(finalPresence).toEqual({
      base: true,
      rail: true,
      controlsWhenTrue: true,
      controlsWhenFalse: false
    });
  });

  it('switches control variants based on edge state', () => {
    jest.useFakeTimers();
    render(<Scroller>{sampleChildren}</Scroller>);
    const base = document.querySelector('[data-slot="base"]') as HTMLDivElement;
    const viewport = document.querySelector('[data-slot="_viewport"]') as HTMLDivElement;
    const geometry = configureGeometry(viewport, { clientWidth: 320, scrollWidth: 1920 });

    const prevButton = screen.getByRole('button', { name: 'Scroll left' });
    const nextButton = screen.getByRole('button', { name: 'Scroll right' });

    const initialSnapshot = {
      prevLight: prevButton.className.includes('bg-comp-button-color-background-default-blur'),
      nextBrand: nextButton.className.includes('bg-comp-button-primary-color-background-default'),
      startFlag: base.className.includes('[--scroller-edge-start:1]')
    };

    act(() => {
      prevButton.focus();
      nextButton.click();
      jest.runOnlyPendingTimers();
    });

    const midSnapshot = {
      prevBrand: prevButton.className.includes('bg-comp-button-primary-color-background-default')
    };

    act(() => {
      viewport.scrollBy({ left: geometry.getMaxScrollLeft(), behavior: 'auto' });
      jest.runOnlyPendingTimers();
    });

    const endSnapshot = {
      nextLight: nextButton.className.includes('bg-comp-button-color-background-default-blur'),
      endFlag: base.className.includes('[--scroller-edge-end:1]')
    };

    jest.useRealTimers();

    expect({
      ...initialSnapshot,
      ...midSnapshot,
      ...endSnapshot,
      finalStartFlag: base.className.includes('[--scroller-edge-start:1]')
    }).toEqual({
      prevLight: true,
      nextBrand: true,
      startFlag: true,
      prevBrand: true,
      nextLight: true,
      endFlag: true,
      finalStartFlag: false
    });
  });

  it('paginates by viewport and fixed steps', () => {
    jest.useFakeTimers();
    const { rerender } = render(<Scroller pageBy="viewport">{sampleChildren}</Scroller>);
    const viewport = document.querySelector('[data-slot="_viewport"]') as HTMLDivElement;
    const geometry = configureGeometry(viewport, { clientWidth: 300, scrollWidth: 1500 });

    const next = screen.getByRole('button', { name: 'Scroll right' });
    const prev = screen.getByRole('button', { name: 'Scroll left' });

    act(() => {
      next.click();
      jest.runOnlyPendingTimers();
    });

    const viewportScroll = geometry.getScrollLeft();

    act(() => {
      prev.click();
      jest.runOnlyPendingTimers();
    });

    rerender(
      <Scroller pageBy="fixed" pageSize={200}>
        {sampleChildren}
      </Scroller>
    );

    act(() => {
      screen.getByRole('button', { name: 'Scroll right' }).click();
      jest.runOnlyPendingTimers();
    });

    const fixedScroll = geometry.getScrollLeft();

    jest.useRealTimers();

    expect({
      viewportStep: viewportScroll,
      fixedStep: fixedScroll
    }).toEqual({
      viewportStep: 300,
      fixedStep: 200
    });
  });

  it('applies stackRows data attribute', () => {
    render(<Scroller stackRows>{sampleChildren}</Scroller>);
    const rail = document.querySelector('[data-slot="_rail"]') as HTMLElement;
    const attributeSnapshot = {
      stackRows: rail.getAttribute('data-stack-rows')
    };
    expect(attributeSnapshot).toEqual({
      stackRows: 'true'
    });
  });

  it('emits scroll metrics on mount and subsequent scrolls', () => {
    jest.useFakeTimers();
    const handler = jest.fn();
    render(<Scroller onScrollChange={handler}>{sampleChildren}</Scroller>);
    const viewport = document.querySelector('[data-slot="_viewport"]') as HTMLDivElement;
    configureGeometry(viewport, { clientWidth: 320, scrollWidth: 1600 });

    act(() => {
      jest.runOnlyPendingTimers();
    });

    act(() => {
      viewport.scrollBy({ left: 320, behavior: 'auto' });
      jest.runOnlyPendingTimers();
    });

    jest.useRealTimers();

    const formattedCalls = handler.mock.calls.map(([metrics]) => metrics);

    expect({
      callCount: handler.mock.calls.length,
      first: formattedCalls[0],
      second: formattedCalls[1]
    }).toEqual({
      callCount: 2,
      first: {
        left: 0,
        width: 1600,
        viewport: 320,
        atStart: true,
        atEnd: false
      },
      second: {
        left: 320,
        width: 1600,
        viewport: 320,
        atStart: false,
        atEnd: false
      }
    });
  });
});
